------------------------------------------------------------------
--- LGamePool
------------------------------------------------------------------
function LGameFunction.ClearGamePool(poolName)
	if (gLGamePool) then
		gLGamePool:ClearSimplePool(poolName)
	end
end

function LGameFunction.ClearAllGamePool()
	if (gLGamePool) then
		gLGamePool:ClearAllSimplePool()
	end
end

function LGameFunction:GetSimplePool(poolName)
	if (gLGamePool) then
		return gLGamePool:GetSimplePool(poolName)
	else
		return nil
	end
end

function LGameFunction.CreateSimplePool(poolName, isObjectActive)
	if (gLGamePool) then
		return gLGamePool:CreateSimplePool(poolName, isObjectActive)
	else
		return nil
	end
end

function LGameFunction.PrepareGamePool(poolName, args, func, poolInitSize)
	if (gLGamePool) then
		gLGamePool:PrepareSimplePool(poolName, args, func, poolInitSize)
	else
		LogError("gLGamePool lost ->" .. poolName)
		if (func) then
			func()
		end
	end
end

function LGameFunction.MakeItemASyncFromGamePool(poolName, args, func)
	if (gLGamePool) then
		return gLGamePool:MakeItemASync(poolName, args, func)
	else
		if func ~= nil then
			func(nil, args)
		end
	end
end

function LGameFunction.MakeItemFromGamePool(poolName, args)
	if (gLGamePool) then
		return gLGamePool:MakeItem(poolName, args)
	end
	return nil
end
function LGameFunction.ReturnItemToGamePool(poolName, itemKey, trans)
	local bOk = false
	if (gLGamePool) then
		bOk = gLGamePool:ReturnItem(poolName, itemKey, trans)
	end
	if not bOk then
		LxResUtil.DestroyObject(trans.gameObject)
	end
	return bOk
end

