function LGameFunction.IsInScene(sceneClassName)
	if (gLGameScene) then
		return gLGameScene:IsCurrentScene(sceneClassName)
	end
	return false
end

function LGameFunction.GetNowSceneClass()
	if (gLGameScene) then
		return gLGameScene:GetCurrentScene()
	end
	return nil
end

