---@return LxMainAdapter
function LGameFunction.GetMainScene()
	--if not LGameFunction.IsInScene("LMainScene") then
	--	return nil
	--end
	if not LGameFunction.IsInScene(LevelNames.Main) then
		return nil
	end
	return LGameFunction.GetNowSceneClass()
end

function LGameFunction.IsInMainScene()
	--return LGameFunction.IsInScene("LMainScene")
	return LGameFunction.IsInScene(LevelNames.Main)
end

function LGameFunction.ChangeMap(className,isTransit, arg)
	local scene = LGameFunction.GetMainScene()
	if scene then
		-- post test
		--[[
		gLGamePostProcess:ChangeMapEffect(scene:GetSceneMainCamera(), function()
			scene:ChangeMap(className,arg)
		end)
		--]]

		-- 引导跳转，功能切换，其它跳转，只要剧情引导未完成，都转成剧情地图
		--if className == "LFightIdleMap" and not gModelGuideStory:IsGuideStoryFinish() then
		--	gModelGuideStory:EnterGuideMap()
		--	return
		--end
		scene:ChangeMap(className, isTransit, arg)
	end
end

function LGameFunction.GetCurMap()
	local scene = LGameFunction.GetMainScene()
	if not scene then return nil end
	return scene:GetCurMap()
end

function LGameFunction.ShakeMainScene(time,intensityX,intensityY)
	local scene = LGameFunction.GetMainScene()
	if scene then scene:ShakeMainScene(time,intensityX,intensityY) end
end

