end

function LGameFunction.CloseUIBtBackground()
	--gprint("CloseUIBtBackground", LGameSettings.isNotBootBackground)
	if LGameSettings.isNotBootBackground then
		CS.CallCsFun(CsFunType.HideLaunchScreen)
	else
		if CS.IsWebGL() then
			CS.CallCsFun(CsFunType.HideLaunchScreen)
		end
		GF.CloseWndByName("UIBtBackground")
	end
end

