function LGameFunction.ShowAlert(alertData)
	if gLGameUI then
		gLGameUI:OpenWndWithLayer(LGameUI.UI_SORTLAYER_UIGUIDE, 'UISysAlert', alertData)
	end
end

function LGameFunction.ShowMessage(message)
	local errMsg = tostring(message)
	if string.isempty(errMsg) then
		return
	end

	--判断是否有没打开
	if LGameSettings.isLoginAfter and not GF.FindFirstWndByName("UISisMsg")  then
		GF.OpenWndDebug("UISisMsg", { msg = errMsg })
	else
		FireEvent(EventNames.ON_SYS_MSG, errMsg)
	end

end

